import ldap

def search_user_by_username(ldap_server, base_dn, username):
    try:
        l = ldap.initialize(f"ldap://{ldap_server}")
        l.set_option(ldap.OPT_REFERRALS, 0)
        l.simple_bind_s()

        search_filter = f"(uid={username})"
        attributes = ['cn', 'mail']
        
        result_id = l.search(base_dn, ldap.SCOPE_SUBTREE, search_filter, attributes)
        results = []
        
        while True:
            result_type, result_data = l.result(result_id, 0)
            if result_data == [] and result_type == -1:
                break
            elif result_type == ldap.RES_SEARCH_ENTRY:
                results.append(result_data[0][1])
        
        l.unbind_s()
        return results
    
    except ldap.LDAPError as e:
        print(f"LDAP error: {e}")
        return []

